SELECT * FROM b_project


        AND (INSTR(project_no, #{query.searchWord}) OR INSTR(project_name, #{query.searchWord}) OR INSTR(manager_name, #{query.searchWord}))


        AND INSTR(project_no, #{query.projectNo})


        AND INSTR(project_name, #{query.projectName})


        AND project_type = #{query.projectType}


        AND project_status = #{query.projectStatus}


        AND INSTR(manager_name, #{query.managerName})


        AND start_date >= #{query.startDateBegin}


        AND start_date <= #{query.startDateEnd}


        AND deleted_flag = #{query.deletedFlag}



    ORDER BY project_id DESC

SELECT * FROM b_project
WHERE project_no = #{projectNo}
LIMIT 1

SELECT * FROM b_project
WHERE deleted_flag = #{deletedFlag}
ORDER BY project_id DESC
